import{_ as d,o as e,c as r,ai as a}from"./chunks/framework.BSOyxTN6.js";const u=JSON.parse('{"title":"Rust中的数字类型","description":"","frontmatter":{},"headers":[],"relativePath":"basic-docs/Number/readme.md","filePath":"basic-docs/Number/readme.md"}'),i={name:"basic-docs/Number/readme.md"};function s(n,t,o,h,l,$){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="rust中的数字类型" tabindex="-1">Rust中的数字类型 <a class="header-anchor" href="#rust中的数字类型" aria-label="Permalink to “Rust中的数字类型”">​</a></h1><h2 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to “分类”">​</a></h2><p>Rust中的数字类型是<strong>静态类型</strong>且为<strong>强类型</strong>，编译的时候就会确定类型不会隐式转换。</p><ol><li>整数类型（Integer）：无小数部分</li><li>浮点数类型（Float）：有小数部分</li></ol><h3 id="整数类型" tabindex="-1">整数类型 <a class="header-anchor" href="#整数类型" aria-label="Permalink to “整数类型”">​</a></h3><p>命名规则：{u/i}{8/16/32/64/128/size} 如果类型是usize/isize表示数的类型跟系统位数关联，比如64位系统就是u64/i64。</p><p>u=unsigned（无符号，只能表示0和正数，usigned类型没有符号位） i=signed（有符号，可表示正数、负数、0，signed类型有一位表示符号位）</p><p>取值范围</p><table tabindex="0"><thead><tr><th>类型</th><th>取值范围</th></tr></thead><tbody><tr><td>i8</td><td>-128 到 127</td></tr><tr><td>u8</td><td>0 到 255</td></tr><tr><td>i16</td><td>$-2^{15}$ 到 $2^{15}-1$</td></tr><tr><td>u16</td><td>0 到 $2^{16}-1$</td></tr><tr><td>i32</td><td>$-2^{31}$ 到 $2^{31}-1$</td></tr><tr><td>u32</td><td>0 到 $2^{32}-1$</td></tr><tr><td>i64</td><td>$-2^{63}$ 到 $2^{63}-1$</td></tr><tr><td>u64</td><td>0 到 $2^{64}-1$</td></tr><tr><td>i128</td><td>$-2^{127}$ 到 $2^{127}-1$</td></tr><tr><td>u128</td><td>0 到 $2^{128}-1$</td></tr></tbody></table><p>要注意无符号整数如果相减为负数的话会溢出</p><h3 id="浮点数类型" tabindex="-1">浮点数类型 <a class="header-anchor" href="#浮点数类型" aria-label="Permalink to “浮点数类型”">​</a></h3><p>f32与f64</p><table tabindex="0"><thead><tr><th>类型</th><th>取值范围</th><th>精度</th></tr></thead><tbody><tr><td>f32</td><td>范围很大，不方便透露</td><td>--</td></tr><tr><td>f64</td><td>范围很大，不方便透露</td><td>--</td></tr></tbody></table>',13)])])}const b=d(i,[["render",s]]);export{u as __pageData,b as default};
